var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"젠장, 하필 이런 때에 침식사태라니. 지원을 기대할 수 있긴 한 건가?","JPN":"くそ、よりによってこんな時に侵食事態なんて。支援なんてしてくれるのか？","ENG":"Damn it, another Corruption disaster?! I don’t think there’s going to be any backup...","TWN":"可惡！偏偏挑這種時候發生侵蝕事件，那還會有人來支援嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"지휘차량이 전복됐다! 경로를 수정해!","JPN":"指揮車両が転覆した！　経路を修正しろ！","ENG":"Vehicle down! Change routes!","TWN":"指揮車翻覆！修正路線！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L7_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"앞 교차로에서 수송차를 셋으로 나눠서 움직인다. 놈들의 시선을 분산시켜!","JPN":"この先の交差路で輸送車を三つに分けて動く。やつらの視線を分散させろ！","ENG":"We divide into three groups at the next intersection. Distract the enemies!","TWN":"在前面的岔路車隊分三路行駛！分散敵人的注意！"},"stage":{"bg":"HIGHWAY_NORMAL","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DRIVER_NPC_ALPHA_NULL","text":{"KOREA":"이봐. 우리 쪽 꼬리는 어때?","JPN":"おい。後ろどうだ？","ENG":"Hey. How’s the trail behind us?","TWN":"後面情況如何？"},"stage":{"bg":"VEHICLE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"다행히 쫓아오지 않는 것 같군.","JPN":"幸い付いてきてはいないようだな。","ENG":"I don’t think they’re following us.","TWN":"幸好沒追上來的樣子。"},"stage":{"bg":"VEHICLE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRIVER_NPC_ALPHA_NULL","text":{"KOREA":"하하…… 그럼 따돌린 건가?","JPN":"はは……じゃあ、うまく撒いたのか？","ENG":"Ha ha... I guess we got away.","TWN":"呼……那要掉頭嗎？"},"stage":{"bg":"VEHICLE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"쿨럭쿨럭……","JPN":"ゲホゲホッ……","ENG":"*Cough!* *Cough!*","TWN":"咳咳咳……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"C컨테이너! 무슨 일이지? 교전인가?","JPN":"Cコンテナ！　どうした？　交戦か？","ENG":"Container C! What’s going on? Any enemy interaction?","TWN":"C車！發生什麼事？雙方交火嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L22_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"그…… 그게……","JPN":"そ……それが……","ENG":"I-I...","TWN":"車……車子……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"차량이 갑자기 반으로 갈라졌습니다.","JPN":"車両がいきなり半分に割れました。","ENG":"The vehicle got cut in half.","TWN":"車子突然斷成二截。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"……뭐라고? 죄수는 어떻게 됐지? 어서 상태 확인해!","JPN":"……何だと？　囚人はどうなった？　急いで状態を確認しろ！","ENG":"...What? What happened to the prisoner? Go see him now!","TWN":"……你說什麼？那犯人情況如何？趕快確認！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"지, 지금 확인해보겠습니다!","JPN":"い、今確認してみます！","ENG":"Y-yes sir, right away...!","TWN":"是…是的，馬上確認！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"이보게! 어떻게 됐지? 죄수가 다치기라도 했나?","JPN":"おい！　どうなった？　囚人が怪我でもしたのか？","ENG":"So? How is he? Is he hurt?","TWN":"喂！怎麼樣？犯人有受傷嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"……사라졌어요.","JPN":"……消えました。","ENG":"...He’s gone.","TWN":"……不見了。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"죄수가 보이지 않습니다!","JPN":"囚人が見あたりません！","ENG":"We lost him!","TWN":"犯人不見了！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"가져왔어요, 아버지.","JPN":"持ってきましたわ、お父様。","ENG":"I got him, father.","TWN":"父親，我把人帶來了。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GENERAL_NPC_NOA_QM","text":{"KOREA":"오랜만이오, 하바키.","JPN":"久しぶりだな、覇吐。","ENG":"Long time no see, Habaki.","TWN":"幅木，好久不見了。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_QM","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"끄으응…… 충격으로 머리가 지끈거리는군.","JPN":"ぐぬぬ……衝撃で頭がずきずきするわ。","ENG":"Urgh... My head still hurts from the impact...","TWN":"呃呃……剛才的撞擊力弄得我頭好疼。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_QM","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"유다, 구출 작전이라고 했으면서 이 방식이 최선이었나?","JPN":"ユダ、救出作戦と言っていたがこれが最善だったのか？","ENG":"Was this not a rescue plan, Judas?","TWN":"尤達，這就是你說的劫獄計畫嗎？難道沒有更好的方式嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_QM","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"미안하군. 내 딸이 조금 과격해서 말이지.","JPN":"すまない。娘は少々過激でな。","ENG":"My apologies. Lenore can get a little carried away at times.","TWN":"真是抱歉，小女個性比較激進一點。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"하지만 계획이 성공하고 그대가 무사할 것이라는 건 관측을 통해 확실히 알고 있었다오.","JPN":"だが、計画は成功し、そなたが無事であるということは観測で知っていたのだ。","ENG":"But through foresight, I was convinced that the plan would succeed, and you will be safe.","TWN":"不過透過觀測，我確認計畫是成功的，而你也沒有受傷。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"관측이라고……? 설마 오라클 프로젝트가 정말로 성공한 건가?","JPN":"観測だと……？　まさかオラクルプロジェクトが本当に成功したのか？","ENG":"Foresight...? Was the Oracle project a success?","TWN":"觀測……？難道甲骨文計畫真的成功了嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"소개하지. 이쪽은 내 하나뿐인 딸인 레노어요.","JPN":"紹介しよう。これが一人娘のレノアだ。","ENG":"Allow me to introduce my one and only daughter, Lenore.","TWN":"介紹一下，這位是我唯一的女兒，蕾諾雅。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"딸이라. 자네가 자식을 둘 정도로 가족애가 있는 줄은 몰랐군.","JPN":"娘か。お前が子を持つほど家族愛がある人間とは知らなかったな。","ENG":"A daughter, you say? I never assumed you were affectionate enough to keep a family.","TWN":"你女兒？沒想到你是家庭觀念這麼重的人，竟然還生孩子。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"결과론적으로는…… 그럴 만한 가치가 있었지.","JPN":"結果論的には……それだけの価値があったのだ。","ENG":"It was worth it... eventually.","TWN":"就結果而言……是值得的。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"가면을 벗어라, 레노어.","JPN":"仮面を脱げ、レノア。","ENG":"Remove your mask, Lenore.","TWN":"脫下面具，蕾諾雅。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"네, 아버지.","JPN":"はい、お父様。","ENG":"Yes, father.","TWN":"是，父親。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"저…… 저 눈은?!","JPN":"そ……その目は！？","ENG":"Those eyes...!","TWN":"……她的眼睛？！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"설마 자기 딸에게 무녀의 신체를 이식한 건가?","JPN":"まさか自分の娘に巫女の体を移植したのか？","ENG":"Have you implanted the priestess’s body on your daughter?","TWN":"你該不會是把巫女的身體移植到你的女兒身上吧？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그렇소. 힘을 해석하는 과정에서 부작용이 조금 있긴 했지만, 결과적으로는 성공했다오.","JPN":"そうだ。力を解釈する過程で少々副作用が起きたが、結果的には成功したのだ。","ENG":"Correct. Albeit the minor side effects while getting used to its powers, the result came out beautifully.","TWN":"沒錯，雖然相容過程中有產生一點副作用，但結果而言是成功的。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"허허……","JPN":"ほほう……","ENG":"Ha ha...","TWN":"呵呵……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"정말로 무녀를 만들어내는 데 성공하다니…… 역시 수단방법을 가리지 않는 과학자는 다르군.","JPN":"本当に巫女を作り出すことに成功するとは……やはり手段を選ばない科学者は違うな。","ENG":"I cannot believe that you actually succeeded in creating a priestess... Even without morals, you are a talented scientist after all.","TWN":"竟然真的成功製造出巫女……為達目的不擇手段的科學家就是不一樣呢。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"내 동의도 없이 원본을 훼손한 건 괘씸하지만, 성과를 거뒀으니 넘어가도록 하지.","JPN":"わしの同意なしでオリジナルを傷つけたことはけしからんが、成果をあげたのだから許すとしよう。","ENG":"While I am dismayed that you damaged the bodies without my consent, you will be excused for the achievements you have made.","TWN":"雖然我不是很高興你未經我的同意便毀損正本，但看在有獲取成果的份上就不跟你計較。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"고맙소. 그대가 오랜 기간에 걸쳐 우리에게 협조하고, 실험소재를 제공해준 덕분이라오.","JPN":"感謝する。そなたが長い間我らに協力し、実験の素材を提供してくれたおかげだ。","ENG":"You have my thanks. It was all due to your continued cooperation and supply of test subjects that we were able to come this far.","TWN":"謝謝，這都要歸功於你長期對我們的協助，以及提供實驗材料。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"하지만 아직은 완벽하진 않아. 지금까지 제공받은 샘플만으로는 아직 목적의 절반에도 다다르지 못했으니 말이지.","JPN":"だがまだ完全ではない。今まで提供してもらったサンプルだけでは、目標の半分も達成できてないのだからな。","ENG":"Nevertheless, perfection lies far ahead. With the samples we have received so far, we are less than half way of what we aim to achieve.","TWN":"但這還不是最完美的結果，以目前拿到的樣本，距離目標還有一大段的距離。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"흐흐, 그거라면 걱정 마시게. 아직 최고의 실험재료가 남아있으니 말이야.","JPN":"ふふ、それなら安心してくれ。まだ最高の実験材料が残っているからな。","ENG":"Ha ha, you needn’t worry about that. You haven’t tried the best test subject I have ready for you.","TWN":"呵呵，這你不用擔心，我們還有最棒的實驗材料。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"우리에게 미래를 보는 힘이 있다면 그깟 나나하라 당주쯤 산 채로 잡아들이는 건 문제도 아니지.","JPN":"わしらに未来を見る力があれば、七原家当主を生け捕りするくらい赤子の手をひねるようなものだ。","ENG":"With the ability to see the future, we will capture Lady Nanahara in no time.","TWN":"若我們有可以預知未來的能力，那要活捉七原堂主我想不是問題。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"물론, 우리는 지금껏 그래왔듯 그대의 계획에 적극적으로 협조할 것이오.","JPN":"もちろん、我らは今までどおりそなたの計画に積極的に協力するつもりだ。","ENG":"We shall maintain our teamwork, just like the way we always have.","TWN":"當然，而我們將一如既往，積極協助你的計劃。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"하지만 그 전에, 약속한 샘플을 받아 두고 싶은데.","JPN":"だがその前に、約束したサンプルをもらっておきたい。","ENG":"But before that, I wish to receive the sample you promised us before.","TWN":"不過在那之前，我想先拿到說好的樣本。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"샘플은 확보해 뒀다. 하지만 지금은 넘겨줄 수 없어.","JPN":"サンプルは確保しておいた。だが今は引き渡せない。","ENG":"The sample is secured. But I will not hand it over now.","TWN":"樣本沒問題，但還不能給你。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"어째서지?","JPN":"なぜだ？","ENG":"How is that?","TWN":"原因是？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"우리의 협력은 어디까지나 신뢰가 아닌 거래에 의한 것이니까.","JPN":"わしらの協力関係は信頼ではなく取引によって成り立つものだからだ。","ENG":"Our so called \\"teamwork\\" is based on mutual profit, not trust.","TWN":"因為我們的合作不是建立在互信的基礎上，而是單純的交易。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"나는 연구에 쓰일 재료를, 자네는 그것을 응용할 기술력을.","JPN":"わしは研究に使う材料を、お前はそれを応用する技術力を。","ENG":"I provide the test subjects, you provide the technology to process them.","TWN":"我負責提供研究材料，你負責提供技術。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그런데 연합을 등지는 대가로 쫓겨난 내가 그것마저 쉽게 넘겨줘버리면, 자네가 무엇 때문에 내 명령을 듣겠나?","JPN":"だが連合を裏切って追い出されたわしが、取引材料を簡単に引き渡してしまったら、お前はわしの命令を聞くかの？","ENG":"Now that I am officially banished from the Alliance, I have no guarantee that you will listen to me afterwards if I hand over what you want.","TWN":"然而我現在因為背叛聯盟而遭到驅逐，要是輕易將東西交給你，那你怎麼會繼續聽命於我？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"실망스럽지만, 충분히 합리적인 판단이오.","JPN":"残念だが、十分合理的な判断だ。","ENG":"Although I must say that I am rather disheartened, your logic is strong.","TWN":"真是令人失望，不過確實是合理的判斷。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그렇다면 다음 계획의 타깃은 당주로 정해졌군.","JPN":"だとすると、次の計画のターゲットは当主になるな。","ENG":"Then our next target must be Lady Nanahara.","TWN":"那下次計畫的目標就是堂主了。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"가문연합이 쉽게 당해주진 않을 게야. 우선은 본국으로 돌아가 만반의 준비를 한 뒤에……","JPN":"連合はそう簡単にやられてはくれんだろう。まずは本国に戻り万全の準備をしてから……","ENG":"The Alliance will not be an easy enemy to deal with. I advise that you go back to your homeland and prepare–","TWN":"家族聯盟可沒那麼好對付，你先回國做好萬全的準備……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그건 걱정마시오. 놈들을 사로잡기 위한 그물을 이미 쳐 놓았으니.","JPN":"それは心配するな。やつらをとらえるための網はすでに打ってある。","ENG":"That will not be necessary. We have already set a trap for them.","TWN":"這你可以放心，我早已佈下天羅地網。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그게 정말인가? 하지만 어떻게 벌써……?","JPN":"それは本当か？　だがこんなに早くからどうやって……？","ENG":"Is that so? But how...?","TWN":"此話當真？不過怎麼會那麼快就……？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"허허…… 그렇군. 이것이 바로 예견의 힘인가?","JPN":"ほほう……そうか。これが予言の力なのか？","ENG":"Ha ha... I see. So it is the power of foresight.","TWN":"呵呵……原來如此，這就是預知的力量嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그렇다면 이 싸움의 결말도 이미 정해진 거나 마찬가지겠군.","JPN":"それならこの戦いの結末もすでに決まっているも同然だな。","ENG":"Then this fight must be destined to be end as our victory.","TWN":"那也就等於這場戰爭的結局已定囉？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"물론. 우리는 관측을 통해 최소한의 손실만으로 무녀를 사로잡게 될 거요.","JPN":"もちろんだ。我々は観測を通じて最低限の損失で巫女をとらえることになるだろう。","ENG":"Of course. We will capture the priestess with minimal loss.","TWN":"當然，我們會透過觀測，在將損失降到最低的情況下活捉巫女。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아버지, 곧 올 거예요.","JPN":"お父様、もうすぐ来ます。","ENG":"Father, they’re coming.","TWN":"父親，我去去就回。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"몸을 낮춰서 피하시오, 하바키.","JPN":"身を低くされよ、覇吐。","ENG":"Keep low, Habaki.","TWN":"把身子壓低，幅木。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"음? 유다. 갑자기 무슨 소릴……","JPN":"む？　ユダ。急に何を……","ENG":"Mm? Judas, what are you talking abou–","TWN":"嗯？怎麼突然要我……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"하, 하야미?! 네가 왜 여기에 있지?","JPN":"は、速水！？　どうしてお前がここにいるのだ？","ENG":"H-Hayami?! Why are you here?","TWN":"速…速水？！你怎麼會在這裡？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"네놈들이 하바키의 배후로구나.","JPN":"お前らが覇吐の後ろ盾か。","ENG":"You must be Habaki’s cooperators.","TWN":"原來你們就是幅木的靠山。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"하야미 가문의 후손, 하야미 사나에.","JPN":"速水家の末裔、速水早苗。","ENG":"Hayami Sanae from the Hayami family.","TWN":"速水家族的後裔，速水早苗。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"하바키에게 얘기 들었소.","JPN":"覇吐から聞いたぞ。","ENG":"I heard about you from Habaki.","TWN":"我聽幅木說過你的事，"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"뛰어난 무사가문의 후예임에도 모친이 살해된 트라우마 때문에 검을 휘두르지 못한다지.","JPN":"優れた武士家の末裔であるにもかかわらず、母親が殺害されたトラウマで刀を振るうことができないらしいな。","ENG":"Despite coming from an honorable warrior family, you cannot use your sword due to the trauma of witnessing the death of your mother.","TWN":"你出身自優秀的武士家族，但母親遇害後產生創傷症候群，於是再也無法拿劍。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"……하야미 가문은 연합의 위협이 되는 자 앞에서만 검을 뽑는다.","JPN":"……速水家は連合を脅かす者の前でのみ刀を抜く。","ENG":"...Hayamis only draw their blade in front of those who are a threat.","TWN":"……速水家族只有在面對威脅到聯盟的人才會拔劍。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"네놈들에게 검을 휘두를 가치가 있는지는 내 직접 눈으로 판단해주마.","JPN":"お前らに刀を振るう価値があるかどうかは私が直接自分の目で判断してやろう。","ENG":"I shall be the one to judge whether you are enough of a threat or not.","TWN":"至於你們，我會親眼判斷是否值得我拔劍。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};